import{_ as d,o as e,c as o,ag as c}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Database Schema","description":"","frontmatter":{},"headers":[],"relativePath":"api/database.md","filePath":"api/database.md"}'),a={name:"api/database.md"};function r(i,t,n,s,l,h){return e(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="database-schema" tabindex="-1">Database Schema <a class="header-anchor" href="#database-schema" aria-label="Permalink to &quot;Database Schema&quot;">​</a></h1><p>SendGrail creates four custom database tables to store connection configurations, email logs, tracking events, and routing rules. All tables use the standard WordPress table prefix (typically <code>wp_</code>).</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Table</th><th>Purpose</th></tr></thead><tbody><tr><td><code>wp_sendgrail_connections</code></td><td>SMTP connection configurations</td></tr><tr><td><code>wp_sendgrail_email_logs</code></td><td>Email delivery log entries</td></tr><tr><td><code>wp_sendgrail_email_events</code></td><td>Tracking events (sent, opened, clicked, failed)</td></tr><tr><td><code>wp_sendgrail_email_routes</code></td><td>Conditional email routing rules</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Migrations run automatically on plugin activation and on version updates. The current database schema version is tracked in the WordPress options table under the key <code>sendgrail_db_version</code>.</p></div><hr><h2 id="wp-sendgrail-connections" tabindex="-1"><code>wp_sendgrail_connections</code> <a class="header-anchor" href="#wp-sendgrail-connections" aria-label="Permalink to &quot;`wp_sendgrail_connections`&quot;">​</a></h2><p>Stores SMTP connection configurations. Each row represents a single SMTP provider connection.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Nullable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>BIGINT(20) UNSIGNED</code></td><td>No</td><td>Auto-increment</td><td>Primary key</td></tr><tr><td><code>name</code></td><td><code>VARCHAR(255)</code></td><td>No</td><td>—</td><td>Display name for the connection</td></tr><tr><td><code>provider</code></td><td><code>VARCHAR(100)</code></td><td>No</td><td>—</td><td>Provider slug (e.g., <code>gmail</code>, <code>sendgrid</code>, <code>ses</code>)</td></tr><tr><td><code>host</code></td><td><code>VARCHAR(255)</code></td><td>No</td><td>—</td><td>SMTP server hostname</td></tr><tr><td><code>port</code></td><td><code>INT(5) UNSIGNED</code></td><td>No</td><td><code>587</code></td><td>SMTP port number</td></tr><tr><td><code>encryption</code></td><td><code>VARCHAR(10)</code></td><td>No</td><td><code>tls</code></td><td>Encryption type: <code>tls</code>, <code>ssl</code>, or <code>none</code></td></tr><tr><td><code>from_email</code></td><td><code>VARCHAR(255)</code></td><td>No</td><td>—</td><td>Sender email address</td></tr><tr><td><code>from_name</code></td><td><code>VARCHAR(255)</code></td><td>Yes</td><td><code>NULL</code></td><td>Sender display name</td></tr><tr><td><code>auth</code></td><td><code>TINYINT(1)</code></td><td>No</td><td><code>1</code></td><td>Whether SMTP authentication is required</td></tr><tr><td><code>username</code></td><td><code>VARCHAR(255)</code></td><td>Yes</td><td><code>NULL</code></td><td>SMTP authentication username</td></tr><tr><td><code>password</code></td><td><code>TEXT</code></td><td>Yes</td><td><code>NULL</code></td><td>Encrypted SMTP password</td></tr><tr><td><code>is_enabled</code></td><td><code>TINYINT(1)</code></td><td>No</td><td><code>1</code></td><td>Whether the connection is active</td></tr><tr><td><code>is_default</code></td><td><code>TINYINT(1)</code></td><td>No</td><td><code>0</code></td><td>Whether this is the default connection</td></tr><tr><td><code>created_at</code></td><td><code>DATETIME</code></td><td>No</td><td><code>CURRENT_TIMESTAMP</code></td><td>Record creation time (UTC)</td></tr><tr><td><code>updated_at</code></td><td><code>DATETIME</code></td><td>No</td><td><code>CURRENT_TIMESTAMP</code></td><td>Last update time (UTC)</td></tr></tbody></table><p><strong>Indexes:</strong></p><table tabindex="0"><thead><tr><th>Index</th><th>Columns</th><th>Type</th></tr></thead><tbody><tr><td><code>PRIMARY</code></td><td><code>id</code></td><td>Primary</td></tr><tr><td><code>idx_provider</code></td><td><code>provider</code></td><td>Index</td></tr><tr><td><code>idx_is_enabled</code></td><td><code>is_enabled</code></td><td>Index</td></tr><tr><td><code>idx_is_default</code></td><td><code>is_default</code></td><td>Index</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Security Note</p><p>The <code>password</code> column is encrypted using <strong>AES-256-CBC</strong> with a key derived from the WordPress <code>AUTH_KEY</code> salt. Passwords are never stored in plaintext and are decrypted only at the moment of SMTP authentication.</p></div><hr><h2 id="wp-sendgrail-email-logs" tabindex="-1"><code>wp_sendgrail_email_logs</code> <a class="header-anchor" href="#wp-sendgrail-email-logs" aria-label="Permalink to &quot;`wp_sendgrail_email_logs`&quot;">​</a></h2><p>Stores a log entry for every email sent through WordPress <code>wp_mail()</code> while SendGrail is active.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Nullable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>BIGINT(20) UNSIGNED</code></td><td>No</td><td>Auto-increment</td><td>Primary key</td></tr><tr><td><code>connection_id</code></td><td><code>BIGINT(20) UNSIGNED</code></td><td>Yes</td><td><code>NULL</code></td><td>FK to connections table</td></tr><tr><td><code>to</code></td><td><code>TEXT</code></td><td>No</td><td>—</td><td>Recipient email address(es)</td></tr><tr><td><code>from_email</code></td><td><code>VARCHAR(255)</code></td><td>Yes</td><td><code>NULL</code></td><td>Sender email used</td></tr><tr><td><code>from_name</code></td><td><code>VARCHAR(255)</code></td><td>Yes</td><td><code>NULL</code></td><td>Sender name used</td></tr><tr><td><code>subject</code></td><td><code>VARCHAR(255)</code></td><td>Yes</td><td><code>NULL</code></td><td>Email subject line</td></tr><tr><td><code>body</code></td><td><code>LONGTEXT</code></td><td>Yes</td><td><code>NULL</code></td><td>Full email body (if body logging is enabled)</td></tr><tr><td><code>headers</code></td><td><code>TEXT</code></td><td>Yes</td><td><code>NULL</code></td><td>Email headers as JSON</td></tr><tr><td><code>attachments</code></td><td><code>TEXT</code></td><td>Yes</td><td><code>NULL</code></td><td>Attachment file paths as JSON array</td></tr><tr><td><code>status</code></td><td><code>VARCHAR(20)</code></td><td>No</td><td><code>pending</code></td><td>Delivery status: <code>pending</code>, <code>sent</code>, <code>failed</code></td></tr><tr><td><code>error_message</code></td><td><code>TEXT</code></td><td>Yes</td><td><code>NULL</code></td><td>Error message if delivery failed</td></tr><tr><td><code>tracking_id</code></td><td><code>VARCHAR(64)</code></td><td>Yes</td><td><code>NULL</code></td><td>Unique ID for open/click tracking</td></tr><tr><td><code>retries</code></td><td><code>TINYINT(3) UNSIGNED</code></td><td>No</td><td><code>0</code></td><td>Number of fallback retry attempts</td></tr><tr><td><code>created_at</code></td><td><code>DATETIME</code></td><td>No</td><td><code>CURRENT_TIMESTAMP</code></td><td>When the email was queued (UTC)</td></tr><tr><td><code>updated_at</code></td><td><code>DATETIME</code></td><td>No</td><td><code>CURRENT_TIMESTAMP</code></td><td>Last status update (UTC)</td></tr></tbody></table><p><strong>Indexes:</strong></p><table tabindex="0"><thead><tr><th>Index</th><th>Columns</th><th>Type</th></tr></thead><tbody><tr><td><code>PRIMARY</code></td><td><code>id</code></td><td>Primary</td></tr><tr><td><code>idx_connection_id</code></td><td><code>connection_id</code></td><td>Index</td></tr><tr><td><code>idx_status</code></td><td><code>status</code></td><td>Index</td></tr><tr><td><code>idx_tracking_id</code></td><td><code>tracking_id</code></td><td>Unique</td></tr><tr><td><code>idx_created_at</code></td><td><code>created_at</code></td><td>Index</td></tr><tr><td><code>idx_status_created</code></td><td><code>status</code>, <code>created_at</code></td><td>Composite</td></tr></tbody></table><hr><h2 id="wp-sendgrail-email-events" tabindex="-1"><code>wp_sendgrail_email_events</code> <a class="header-anchor" href="#wp-sendgrail-email-events" aria-label="Permalink to &quot;`wp_sendgrail_email_events`&quot;">​</a></h2><p>Records granular tracking events associated with email log entries. Each email can have multiple events over its lifecycle.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Nullable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>BIGINT(20) UNSIGNED</code></td><td>No</td><td>Auto-increment</td><td>Primary key</td></tr><tr><td><code>email_log_id</code></td><td><code>BIGINT(20) UNSIGNED</code></td><td>No</td><td>—</td><td>FK to email_logs table</td></tr><tr><td><code>type</code></td><td><code>VARCHAR(20)</code></td><td>No</td><td>—</td><td>Event type: <code>sent</code>, <code>opened</code>, <code>clicked</code>, <code>failed</code></td></tr><tr><td><code>metadata</code></td><td><code>TEXT</code></td><td>Yes</td><td><code>NULL</code></td><td>Additional event data as JSON</td></tr><tr><td><code>ip_address</code></td><td><code>VARCHAR(45)</code></td><td>Yes</td><td><code>NULL</code></td><td>IP address of the event trigger</td></tr><tr><td><code>user_agent</code></td><td><code>TEXT</code></td><td>Yes</td><td><code>NULL</code></td><td>User agent string (for open/click events)</td></tr><tr><td><code>created_at</code></td><td><code>DATETIME</code></td><td>No</td><td><code>CURRENT_TIMESTAMP</code></td><td>When the event occurred (UTC)</td></tr></tbody></table><p><strong>Indexes:</strong></p><table tabindex="0"><thead><tr><th>Index</th><th>Columns</th><th>Type</th></tr></thead><tbody><tr><td><code>PRIMARY</code></td><td><code>id</code></td><td>Primary</td></tr><tr><td><code>idx_email_log_id</code></td><td><code>email_log_id</code></td><td>Index</td></tr><tr><td><code>idx_type</code></td><td><code>type</code></td><td>Index</td></tr><tr><td><code>idx_created_at</code></td><td><code>created_at</code></td><td>Index</td></tr><tr><td><code>idx_log_type</code></td><td><code>email_log_id</code>, <code>type</code></td><td>Composite</td></tr></tbody></table><p><strong>Event Types:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Metadata</th></tr></thead><tbody><tr><td><code>sent</code></td><td>Email was successfully handed off to the SMTP server</td><td>—</td></tr><tr><td><code>opened</code></td><td>Recipient loaded the tracking pixel</td><td><code>{&quot;count&quot;: 3}</code> for repeated opens</td></tr><tr><td><code>clicked</code></td><td>Recipient clicked a tracked link</td><td><code>{&quot;url&quot;: &quot;https://...&quot;}</code> original link URL</td></tr><tr><td><code>failed</code></td><td>Delivery failed</td><td><code>{&quot;error&quot;: &quot;Connection timed out&quot;}</code></td></tr></tbody></table><hr><h2 id="wp-sendgrail-email-routes" tabindex="-1"><code>wp_sendgrail_email_routes</code> <a class="header-anchor" href="#wp-sendgrail-email-routes" aria-label="Permalink to &quot;`wp_sendgrail_email_routes`&quot;">​</a></h2><p>Stores conditional routing rules that determine which SMTP connection handles an email based on matching criteria.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Nullable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>BIGINT(20) UNSIGNED</code></td><td>No</td><td>Auto-increment</td><td>Primary key</td></tr><tr><td><code>name</code></td><td><code>VARCHAR(255)</code></td><td>No</td><td>—</td><td>Display name for the rule</td></tr><tr><td><code>field</code></td><td><code>VARCHAR(50)</code></td><td>No</td><td>—</td><td>Field to match against</td></tr><tr><td><code>operator</code></td><td><code>VARCHAR(20)</code></td><td>No</td><td>—</td><td>Comparison operator</td></tr><tr><td><code>value</code></td><td><code>VARCHAR(255)</code></td><td>No</td><td>—</td><td>Value to compare against</td></tr><tr><td><code>connection_id</code></td><td><code>BIGINT(20) UNSIGNED</code></td><td>No</td><td>—</td><td>FK to connections table</td></tr><tr><td><code>priority</code></td><td><code>INT(11)</code></td><td>No</td><td><code>0</code></td><td>Sort order (lower number = higher priority)</td></tr><tr><td><code>is_enabled</code></td><td><code>TINYINT(1)</code></td><td>No</td><td><code>1</code></td><td>Whether the rule is active</td></tr><tr><td><code>created_at</code></td><td><code>DATETIME</code></td><td>No</td><td><code>CURRENT_TIMESTAMP</code></td><td>Record creation time (UTC)</td></tr><tr><td><code>updated_at</code></td><td><code>DATETIME</code></td><td>No</td><td><code>CURRENT_TIMESTAMP</code></td><td>Last update time (UTC)</td></tr></tbody></table><p><strong>Indexes:</strong></p><table tabindex="0"><thead><tr><th>Index</th><th>Columns</th><th>Type</th></tr></thead><tbody><tr><td><code>PRIMARY</code></td><td><code>id</code></td><td>Primary</td></tr><tr><td><code>idx_connection_id</code></td><td><code>connection_id</code></td><td>Index</td></tr><tr><td><code>idx_priority</code></td><td><code>priority</code></td><td>Index</td></tr><tr><td><code>idx_is_enabled</code></td><td><code>is_enabled</code></td><td>Index</td></tr><tr><td><code>idx_enabled_priority</code></td><td><code>is_enabled</code>, <code>priority</code></td><td>Composite</td></tr></tbody></table><p><strong>Supported Fields:</strong></p><table tabindex="0"><thead><tr><th>Field Slug</th><th>Description</th></tr></thead><tbody><tr><td><code>from_email</code></td><td>Full sender email address</td></tr><tr><td><code>from_domain</code></td><td>Domain part of the sender email</td></tr><tr><td><code>to_email</code></td><td>Full recipient email address</td></tr><tr><td><code>to_domain</code></td><td>Domain part of the recipient email</td></tr><tr><td><code>subject</code></td><td>Email subject line</td></tr></tbody></table><p><strong>Supported Operators:</strong></p><table tabindex="0"><thead><tr><th>Operator</th><th>Description</th></tr></thead><tbody><tr><td><code>equals</code></td><td>Exact match (case-insensitive)</td></tr><tr><td><code>contains</code></td><td>Substring match</td></tr><tr><td><code>starts_with</code></td><td>Value starts with the specified string</td></tr><tr><td><code>ends_with</code></td><td>Value ends with the specified string</td></tr><tr><td><code>regex</code></td><td>Regular expression match</td></tr></tbody></table><hr><h2 id="entity-relationships" tabindex="-1">Entity Relationships <a class="header-anchor" href="#entity-relationships" aria-label="Permalink to &quot;Entity Relationships&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>wp_sendgrail_connections</span></span>\n<span class="line"><span>  ├── wp_sendgrail_email_logs (connection_id → id)</span></span>\n<span class="line"><span>  └── wp_sendgrail_email_routes (connection_id → id)</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>wp_sendgrail_email_logs</span></span>\n<span class="line"><span>  └── wp_sendgrail_email_events (email_log_id → id)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Foreign key constraints are not enforced at the database level (for compatibility with all MySQL/MariaDB versions). Referential integrity is maintained at the application layer. Deleting a connection will not cascade-delete its logs or routes.</p></div><h2 id="version-tracking" tabindex="-1">Version Tracking <a class="header-anchor" href="#version-tracking" aria-label="Permalink to &quot;Version Tracking&quot;">​</a></h2><p>The database schema version is stored as a WordPress option:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_option</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;sendgrail_db_version&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// e.g., &quot;1.0.0&quot;</span></span></code></pre></div><p>Migrations are executed automatically when SendGrail detects that the stored version is lower than the plugin&#39;s current version. This check runs on every admin page load via the <code>plugins_loaded</code> hook.</p>',44)])])}const m=d(a,[["render",r]]);export{u as __pageData,m as default};
